/* Retrospectiva Semanal — Spotify Squad Health Check style
 * Calcular métricas da semana sobre TODOS os projetos */

const projetos = $('Todos Projetos').first().json || [];
const memoria = $('Memória').first().json || {};
const agora = new Date();
const inicioSemana = new Date(agora);
inicioSemana.setDate(agora.getDate() - 7);

const projs = Array.isArray(projetos) ? projetos : [];

// Projetos que avançaram de etapa esta semana
const avancaram = projs.filter(p => {
  return (p.auditLog || []).some(log =>
    log.action === 'STATE_TRANSITION' && new Date(log.timestamp) > inicioSemana
  );
});

// Transições desta semana
const transicoesSemana = [];
projs.forEach(p => {
  (p.auditLog || []).forEach(log => {
    if (log.action === 'STATE_TRANSITION' && new Date(log.timestamp) > inicioSemana) {
      transicoesSemana.push({ projeto: p.numeroProjeto, cliente: p.clienteNome, de: log.details?.from, para: log.details?.to });
    }
  });
});

// Tarefas criadas vs concluídas
let tarefasCriadas = 0, tarefasConcluidas = 0;
projs.forEach(p => {
  (p.tarefas || []).forEach(t => {
    if (t.dataCriacao && new Date(t.dataCriacao) > inicioSemana) tarefasCriadas++;
    if (t.concluida) tarefasConcluidas++;
  });
});

// Créditos identificados esta semana (projetos com checklist atualizado)
const creditosSemana = projs.reduce((s, p) => {
  return s + ((p.resultadosAuditoria || {}).totalCreditosIdentificados || 0);
}, 0);

// SLAs vencidos
const slasVencidos = projs.filter(p => {
  if (!p._stateEnteredAt || !p._stateEnteredAt[p.etapaAtual]) return false;
  const SLA_MAP = {'Proposta Comercial':14,'Contrato':7,'Procuração':5,'Coleta de Documentos':21,'Análise dos Documentos':10,'Revisão da Apuração':15,'Relatório Final':7,'Aprovação Interna':3,'Apresentação ao Cliente':14,'Escrituração EFD':30};
  const sla = SLA_MAP[p.etapaAtual];
  if (!sla) return false;
  return Math.floor((agora - new Date(p._stateEnteredAt[p.etapaAtual])) / 86400000) > sla;
}).length;

// Gargalo: etapa onde mais projetos estão parados
const etapaCounts = {};
projs.filter(p => p.status === 'ATIVO' || p.status === 'EM_EXECUCAO').forEach(p => {
  etapaCounts[p.etapaAtual] = (etapaCounts[p.etapaAtual] || 0) + 1;
});
const gargalo = Object.entries(etapaCounts).sort((a, b) => b[1] - a[1])[0];

const dados = {
  periodo: inicioSemana.toLocaleDateString('pt-BR') + ' a ' + agora.toLocaleDateString('pt-BR'),
  projetosAvancaram: avancaram.length,
  transicoes: transicoesSemana,
  tarefasCriadas,
  tarefasConcluidas,
  creditosTotalCarteira: creditosSemana,
  slasVencidos,
  gargalo: gargalo ? { etapa: gargalo[0], qtd: gargalo[1] } : null,
  totalAtivos: projs.filter(p => p.status === 'ATIVO' || p.status === 'EM_EXECUCAO').length,
  totalEncerrados: projs.filter(p => p.status === 'ENCERRADO').length,
  padroesHistoricos: memoria.padroes || {}
};

return [{ json: dados }];

